const lines = FILE_CONTENT.split('\n');
const failures = [];
let inFailure = false;
let currentBlock = [];

for (const line of lines) {
  if (line.includes('FAIL') || line.includes('error:') || line.includes('Error:') || line.includes('expected') || line.includes('✗') || line.includes('AssertionError') || line.includes('TypeError') || line.includes('not defined')) {
    inFailure = true;
  }
  if (inFailure) {
    currentBlock.push(line);
    if (currentBlock.length > 5 && (line.trim() === '' || line.includes('at '))) {
      // keep going for stack traces
    }
    if (currentBlock.length > 20) {
      failures.push(currentBlock.join('\n'));
      currentBlock = [];
      inFailure = false;
    }
  }
}
if (currentBlock.length) failures.push(currentBlock.join('\n'));

// Also find test summary
const summaryLines = lines.filter(l => l.includes('pass') || l.includes('fail') || l.includes('skip') || l.includes('tests'));
console.log("=== TEST SUMMARY ===");
console.log(summaryLines.slice(-10).join('\n'));
console.log("\n=== FAILURE BLOCKS (first 5) ===");
console.log(failures.slice(0, 5).join('\n---\n'));

