const lines = FILE_CONTENT.split('\n');
const failures = [];
let inFailure = false;
let failBlock = [];

for (let i = 0; i < lines.length; i++) {
  const line = lines[i];
  if (line.includes('(fail)') || line.includes('FAIL') || line.includes('error:') || line.includes('Expected') || line.includes('Received') || line.includes('evaluation.reasoning') || line.includes('llm_reasoning')) {
    // grab context around it
    const start = Math.max(0, i - 2);
    const end = Math.min(lines.length - 1, i + 5);
    failures.push(lines.slice(start, end + 1).map(l => l.replace(/^.*?Z\s*/, '').trim()).join('\n'));
    failures.push('---');
  }
}

// Also find test summary
for (let i = lines.length - 1; i >= Math.max(0, lines.length - 50); i--) {
  if (lines[i].includes('pass') || lines[i].includes('fail') || lines[i].includes('expect') || lines[i].includes('tests/')) {
    console.log('TAIL:', lines[i].replace(/^.*?Z\s*/, '').trim());
  }
}

console.log('\n=== FAILURE BLOCKS ===');
console.log(failures.slice(0, 30).join('\n'));

