 77→import { setupAcceptanceSuite } from "../acceptance-test-kit";
 78→
 79→export function setupReasoningSuite(
 80→  suiteName: string,
 81→): () => import("../acceptance-test-kit").AcceptanceTestRuntime {
 82→  return setupAcceptanceSuite(suiteName);
 83→}
 84→
 85→// ---------------------------------------------------------------------------
 86→// Workspace Setup Helper
 87→// ---------------------------------------------------------------------------
 88→
 89→/**
 90→ * Creates a test workspace and identity for reasoning tests.
 91→ */
 92→export async function setupReasoningWorkspace(
 93→  baseUrl: string,
 94→  surreal: Surreal,
 95→  suffix: string,
 96→): Promise<{
 97→  user: TestUser;
 98→  workspaceId: string;
 99→  identityId: string;
100→}> {
101→  const { createTestUser, createTestWorkspace } = await import(
102→    "../coding-agent-orchestrator/orchestrator-test-kit"
103→  );
104→
105→  const user = await createTestUser(baseUrl, suffix);
106→  const workspace = await createTestWorkspace(baseUrl, user);
107→
108→  const identityId = `id-${crypto.randomUUID()}`;
